import java.util.ArrayList;

class PhraseAnalyzer {
    private ArrayList<String> shortWords;

    public PhraseAnalyzer() {
        shortWords = new ArrayList<String>();
    }

    public void buildShortWordList(String phrase, int maxLength) {
        shortWords = new ArrayList<String>();
        while (phrase.indexOf(" ") >= 0) {
            int space = phrase.indexOf(" ");
            String word = phrase.substring(0, space);
            if (word.length() <= maxLength) {
                shortWords.add(word);
            }
            phrase = phrase.substring(space + 1);
        }
        if (phrase.length() <= maxLength) {
            shortWords.add(phrase);
        }
    }

    public int countShortWords(String phrase, int maxLength) {
        buildShortWordList(phrase, maxLength);
        return shortWords.size();
    }
}

