import java.util.ArrayList;

class Item {
    private String name;
    private int quantity;
    private double unitPrice;
    public Item(String name, int quantity, double unitPrice) {
        this.name = name;
        this.quantity = quantity;
        this.unitPrice = unitPrice;
    }
