class ShoppingCart {
    private ArrayList<Item> cart;
    public ShoppingCart(ArrayList<Item> items) {
        cart = new ArrayList<Item>(items);
    }
    public ArrayList<Item> getExpensiveItems(double threshold) {
        ArrayList<Item> expensive = new ArrayList<Item>();
        for (Item item : cart) {
            if (item.getQuantity() * item.getUnitPrice() > threshold) {
                expensive.add(item);
            }
        }
        return expensive;
    }
    public double totalExpensiveCost(double threshold) {
        ArrayList<Item> expensive = getExpensiveItems(threshold);
        double total = 0.0;
        for (Item item : expensive) {
            total += item.getQuantity() * item.getUnitPrice();
        }
        return total;
    }
}

