import java.util.ArrayList;

public class WordCollector {
    private ArrayList<String> words;

    public WordCollector() {
        words = new ArrayList<String>();
    }

    public ArrayList<String> getWords() {
        return words;
    }

    public int addLongWords(String phrase, int minLen) {
        int count = 0;
        String remaining = phrase;
        while (remaining.length() > 0) {
            int spaceIdx = remaining.indexOf(" ");
            String word;
            if (spaceIdx == -1) {
                word = remaining;
                remaining = "";
            } else {
                word = remaining.substring(0, spaceIdx);
                remaining = remaining.substring(spaceIdx + 1);
            }
            if (word.length() >= minLen) {
                words.add(word);
                count++;
            }
        }
        return count;
    }

    public int collectFromPhrases(ArrayList<String> phrases, int minLen) {
        int total = 0;
        for (int i = 0; i < phrases.size(); i++) {
            total += addLongWords(phrases.get(i), minLen);
        }
        return total;
    }
}

