import java.util.ArrayList;

public class Meeting {
    private String date;
    private int attendees;
    public Meeting(String d, int a) { date = d; attendees = a; }
    public String getDate() { return date; }
    public int getAttendees() { return attendees; }
}

class AttendanceLog {
    private ArrayList<Meeting> meetings;

    public AttendanceLog(String[] dates, int[] counts) {
        meetings = new ArrayList<Meeting>();
        for (int i = 0; i < dates.length; i++) {
            if (counts[i] >= 0) {
                meetings.add(new Meeting(dates[i], counts[i]));
            }
        }
    }

    public static ArrayList<String> aboveAverageDates(String[] dates, int[] counts) {
        AttendanceLog log = new AttendanceLog(dates, counts);
        ArrayList<String> result = new ArrayList<String>();
        if (log.meetings.size() == 0) {
            return result;
        }
        int total = 0;
        for (int i = 0; i < log.meetings.size(); i++) {
            total += log.meetings.get(i).getAttendees();
        }
        double avg = (double) total / log.meetings.size();
        for (int i = 0; i < log.meetings.size(); i++) {
            if (log.meetings.get(i).getAttendees() > avg) {
                result.add(log.meetings.get(i).getDate());
            }
        }
        return result;
    }
}

