import java.util.ArrayList;

class TempSeries {
    private ArrayList<Integer> readings;

    public TempSeries() {
        readings = new ArrayList<Integer>();
    }

    public void loadFromCSV(String csv) {
        while (readings.size() > 0) {
            readings.remove(0);
        }
        if (csv == null || csv.equals("")) {
            return;
        }
        String s = csv;
        int comma = s.indexOf(",");
        while (comma >= 0) {
            readings.add(Integer.parseInt(s.substring(0, comma)));
            s = s.substring(comma + 1);
            comma = s.indexOf(",");
        }
        readings.add(Integer.parseInt(s));
    }

    public int countHotStreak(String csv, int hotThreshold) {
        loadFromCSV(csv);
        int best = 0;
        int current = 0;
        for (int i = 0; i < readings.size(); i++) {
            if (readings.get(i) > hotThreshold) {
                current++;
                if (current > best) {
                    best = current;
                }
            } else {
                current = 0;
            }
        }
        return best;
    }
}

